    /**
     * @method
     * @name hitbtc#fetchMarkets
     * @description retrieves data on all markets for hitbtc
     * @see https://api.hitbtc.com/#symbols
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} an array of objects representing market data
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.publicGetPublicSymbol(parameters)).join();
            //
            //     {
            //         "AAVEUSDT_PERP":{
            //             "type":"futures",
            //             "expiry":null,
            //             "underlying":"AAVE",
            //             "base_currency":null,
            //             "quote_currency":"USDT",
            //             "quantity_increment":"0.01",
            //             "tick_size":"0.001",
            //             "take_rate":"0.0005",
            //             "make_rate":"0.0002",
            //             "fee_currency":"USDT",
            //             "margin_trading":true,
            //             "max_initial_leverage":"50.00"
            //         },
            //         "MANAUSDT":{
            //             "type":"spot",
            //             "base_currency":"MANA",
            //             "quote_currency":"USDT",
            //             "quantity_increment":"1",
            //             "tick_size":"0.0000001",
            //             "take_rate":"0.0025",
            //             "make_rate":"0.001",
            //             "fee_currency":"USDT",
            //             "margin_trading":true,
            //             "max_initial_leverage":"5.00"
            //         },
            //     }
            //
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object ids = Helpers.objectKeys(response);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(ids)); i++)
            {
                Object id = Helpers.GetValue(ids, i);
                if (Helpers.isTrue(((String)id).endsWith(((String)"_BQX"))))
                {
                    continue;
                }
                Object market = this.safeValue(response, id);
                Object marketType = this.safeString(market, "type");
                Object expiry = this.safeInteger(market, "expiry");
                Object contract = (Helpers.isEqual(marketType, "futures"));
                Object spot = (Helpers.isEqual(marketType, "spot"));
                Object marginTrading = this.safeBool(market, "margin_trading", false);
                Object margin = Helpers.isTrue(spot) && Helpers.isTrue(marginTrading);
                Object future = (!Helpers.isEqual(expiry, null));
                Object swap = (Helpers.isTrue(contract) && !Helpers.isTrue(future));
                Object option = false;
                Object baseId = this.safeString2(market, "base_currency", "underlying");
                Object quoteId = this.safeString(market, "quote_currency");
                Object feeCurrencyId = this.safeString(market, "fee_currency");
                Object base = this.safeCurrencyCode(baseId);
                Object quote = this.safeCurrencyCode(quoteId);
                Object feeCurrency = this.safeCurrencyCode(feeCurrencyId);
                Object settleId = null;
                Object settle = null;
                Object symbol = Helpers.add(Helpers.add(base, "/"), quote);
                Object type = "spot";
                Object contractSize = null;
                Object linear = null;
                Object inverse = null;
                if (Helpers.isTrue(contract))
                {
                    contractSize = this.parseNumber("1");
                    settleId = feeCurrencyId;
                    settle = this.safeCurrencyCode(settleId);
                    linear = (Helpers.isTrue((!Helpers.isEqual(quote, null))) && Helpers.isTrue((Helpers.isEqual(quote, settle))));
                    inverse = !Helpers.isTrue(linear);
                    symbol = Helpers.add(Helpers.add(symbol, ":"), settle);
                    if (Helpers.isTrue(future))
                    {
                        symbol = Helpers.add(Helpers.add(symbol, "-"), expiry);
                        type = "future";
                    } else
                    {
                        type = "swap";
                    }
                }
                Object lotString = this.safeString(market, "quantity_increment");
                Object stepString = this.safeString(market, "tick_size");
                Object lot = this.parseNumber(lotString);
                Object step = this.parseNumber(stepString);
    final Object finalSymbol = symbol;
                final Object finalBase = base;
                final Object finalQuote = quote;
                final Object finalSettle = settle;
                final Object finalSettleId = settleId;
                final Object finalType = type;
                final Object finalSpot = spot;
                final Object finalContract = contract;
                final Object finalLinear = linear;
                final Object finalInverse = inverse;
                final Object finalContractSize = contractSize;
                final Object finalExpiry = expiry;
                            ((java.util.List<Object>)result).add(new java.util.HashMap<String, Object>() {{
                    put( "id", id );
                    put( "symbol", finalSymbol );
                    put( "base", finalBase );
                    put( "quote", finalQuote );
                    put( "settle", finalSettle );
                    put( "baseId", baseId );
                    put( "quoteId", quoteId );
                    put( "settleId", finalSettleId );
                    put( "type", finalType );
                    put( "spot", finalSpot );
                    put( "margin", margin );
                    put( "swap", swap );
                    put( "future", future );
                    put( "option", option );
                    put( "active", true );
                    put( "contract", finalContract );
                    put( "linear", finalLinear );
                    put( "inverse", finalInverse );
                    put( "taker", HitbtcCore.this.safeNumber(market, "take_rate") );
                    put( "maker", HitbtcCore.this.safeNumber(market, "make_rate") );
                    put( "contractSize", finalContractSize );
                    put( "expiry", finalExpiry );
                    put( "expiryDatetime", null );
                    put( "strike", null );
                    put( "optionType", null );
                    put( "feeCurrency", feeCurrency );
                    put( "precision", new java.util.HashMap<String, Object>() {{
                        put( "amount", lot );
                        put( "price", step );
                    }} );
                    put( "limits", new java.util.HashMap<String, Object>() {{
                        put( "leverage", new java.util.HashMap<String, Object>() {{
                            put( "min", HitbtcCore.this.parseNumber("1") );
                            put( "max", HitbtcCore.this.safeNumber(market, "max_initial_leverage", 1) );
                        }} );
                        put( "amount", new java.util.HashMap<String, Object>() {{
                            put( "min", lot );
                            put( "max", null );
                        }} );
                        put( "price", new java.util.HashMap<String, Object>() {{
                            put( "min", step );
                            put( "max", null );
                        }} );
                        put( "cost", new java.util.HashMap<String, Object>() {{
                            put( "min", HitbtcCore.this.parseNumber(Precise.stringMul(lotString, stepString)) );
                            put( "max", null );
                        }} );
                    }} );
                    put( "created", null );
                    put( "info", market );
                }});
            }
            return result;
        });

    }

