    /**
     * @method
     * @name hitbtc#fetchOrderBooks
     * @description fetches information on open orders with bid (buy) and ask (sell) prices, volumes and other data for multiple markets
     * @see https://api.hitbtc.com/#order-books
     * @param {string[]} [symbols] list of unified market symbols, all symbols fetched if undefined, default is undefined
     * @param {int} [limit] max number of entries per orderbook to return, default is undefined
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure} indexed by market symbol
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrderBooks(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object request = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(!Helpers.isEqual(symbols, null)))
            {
                Object marketIdsInner = this.marketIds(symbols);
                Helpers.addElementToObject(request, "symbols", String.join((String)",", (java.util.List<String>)marketIdsInner));
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "depth", limit);
            }
            Object response = (this.publicGetPublicOrderbook(this.extend(request, parameters))).join();
            Object result = new java.util.HashMap<String, Object>() {{}};
            Object marketIds = Helpers.objectKeys(response);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketIds)); i++)
            {
                Object marketId = Helpers.GetValue(marketIds, i);
                Object orderbook = Helpers.GetValue(response, marketId);
                Object symbol = this.safeSymbol(marketId);
                Object timestamp = this.parse8601(this.safeString(orderbook, "timestamp"));
                Helpers.addElementToObject(result, symbol, this.parseOrderBook(Helpers.GetValue(response, marketId), symbol, timestamp, "bid", "ask"));
            }
            return result;
        });

    }

