    /**
     * @method
     * @name hitbtc#fetchPosition
     * @description fetch data on a single open contract trade position
     * @see https://api.hitbtc.com/#get-futures-margin-account
     * @see https://api.hitbtc.com/#get-isolated-margin-account
     * @param {string} symbol unified market symbol of the market the position is held in, default is undefined
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.marginMode] 'cross' or 'isolated' only 'isolated' is supported, defaults to spot-margin endpoint if this is set
     * @param {bool} [params.margin] true for fetching a spot-margin position
     * @returns {object} a [position structure]{@link https://docs.ccxt.com/?id=position-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchPosition(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            Object marketType = null;
            Object marginMode = null;
            var marketTypeparametersVariable = this.handleMarketTypeAndParams("fetchPosition", null, parameters);
            marketType = ((java.util.List<Object>) marketTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marketTypeparametersVariable).get(1);
            var marginModeparametersVariable = this.handleMarginModeAndParams("fetchPosition", parameters);
            marginMode = ((java.util.List<Object>) marginModeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marginModeparametersVariable).get(1);
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("marginMode", "margin")));
            Object response = null;
            if (Helpers.isTrue(!Helpers.isEqual(marginMode, null)))
            {
                response = (this.privateGetMarginAccountIsolatedSymbol(this.extend(request, parameters))).join();
            } else
            {
                if (Helpers.isTrue(Helpers.isEqual(marketType, "swap")))
                {
                    response = (this.privateGetFuturesAccountIsolatedSymbol(this.extend(request, parameters))).join();
                } else if (Helpers.isTrue(Helpers.isEqual(marketType, "margin")))
                {
                    response = (this.privateGetMarginAccountIsolatedSymbol(this.extend(request, parameters))).join();
                } else
                {
                    throw new NotSupported((String)Helpers.add(this.id, " fetchPosition() not support this market type")) ;
                }
            }
            //
            //     [
            //         {
            //             "symbol": "ETHUSDT_PERP",
            //             "type": "isolated",
            //             "leverage": "10.00",
            //             "created_at": "2022-03-19T07:54:35.24Z",
            //             "updated_at": "2022-03-19T07:54:58.922Z",
            //             currencies": [
            //                 {
            //                     "code": "USDT",
            //                     "margin_balance": "7.478100643043",
            //                     "reserved_orders": "0",
            //                     "reserved_positions": "0.303530761300"
            //                 }
            //             ],
            //             "positions": [
            //                 {
            //                     "id": 2470568,
            //                     "symbol": "ETHUSDT_PERP",
            //                     "quantity": "0.001",
            //                     "price_entry": "2927.509",
            //                     "price_margin_call": "0",
            //                     "price_liquidation": "0",
            //                     "pnl": "0",
            //                     "created_at": "2022-03-19T07:54:35.24Z",
            //                     "updated_at": "2022-03-19T07:54:58.922Z"
            //                 }
            //             ]
            //         },
            //     ]
            //
            return this.parsePosition(response, market);
        });

    }

    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        //     [
        //         {
        //             "symbol": "ETHUSDT_PERP",
        //             "type": "isolated",
        //             "leverage": "10.00",
        //             "created_at": "2022-03-19T07:54:35.24Z",
        //             "updated_at": "2022-03-19T07:54:58.922Z",
        //             currencies": [
        //                 {
        //                     "code": "USDT",
        //                     "margin_balance": "7.478100643043",
        //                     "reserved_orders": "0",
        //                     "reserved_positions": "0.303530761300"
        //                 }
        //             ],
        //             "positions": [
        //                 {
        //                     "id": 2470568,
        //                     "symbol": "ETHUSDT_PERP",
        //                     "quantity": "0.001",
        //                     "price_entry": "2927.509",
        //                     "price_margin_call": "0",
        //                     "price_liquidation": "0",
        //                     "pnl": "0",
        //                     "created_at": "2022-03-19T07:54:35.24Z",
        //                     "updated_at": "2022-03-19T07:54:58.922Z"
        //                 }
        //             ]
        //         },
        //     ]
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marginMode = this.safeString(position, "type");
        Object leverage = this.safeNumber(position, "leverage");
        Object datetime = this.safeString(position, "updated_at");
        Object positions = this.safeValue(position, "positions", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object liquidationPrice = null;
        Object entryPrice = null;
        Object contracts = null;
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(positions)); i++)
        {
            Object entry = Helpers.GetValue(positions, i);
            liquidationPrice = this.safeNumber(entry, "price_liquidation");
            entryPrice = this.safeNumber(entry, "price_entry");
            contracts = this.safeNumber(entry, "quantity");
        }
        Object currencies = this.safeValue(position, "currencies", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object collateral = null;
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(currencies)); i++)
        {
            Object entry = Helpers.GetValue(currencies, i);
            collateral = this.safeNumber(entry, "margin_balance");
        }
        Object marketId = this.safeString(position, "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        final Object finalLiquidationPrice = liquidationPrice;
        final Object finalEntryPrice = entryPrice;
        final Object finalContracts = contracts;
        final Object finalCollateral = collateral;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", null );
            put( "symbol", symbol );
            put( "notional", null );
            put( "marginMode", marginMode );
            put( "marginType", marginMode );
            put( "liquidationPrice", finalLiquidationPrice );
            put( "entryPrice", finalEntryPrice );
            put( "unrealizedPnl", null );
            put( "percentage", null );
            put( "contracts", finalContracts );
            put( "contractSize", null );
            put( "markPrice", null );
            put( "lastPrice", null );
            put( "side", null );
            put( "hedged", null );
            put( "timestamp", HitbtcCore.this.parse8601(datetime) );
            put( "datetime", datetime );
            put( "lastUpdateTimestamp", null );
            put( "maintenanceMargin", null );
            put( "maintenanceMarginPercentage", null );
            put( "collateral", finalCollateral );
            put( "initialMargin", null );
            put( "initialMarginPercentage", null );
            put( "leverage", leverage );
            put( "marginRatio", null );
            put( "stopLossPrice", null );
            put( "takeProfitPrice", null );
        }});
    }

