    /**
     * @method
     * @name hitbtc#fetchOpenInterests
     * @description Retrieves the open interest for a list of symbols
     * @see https://api.hitbtc.com/#futures-info
     * @param {string[]} [symbols] a list of unified CCXT market symbols
     * @param {object} [params] exchange specific parameters
     * @returns {object[]} a list of [open interest structures]{@link https://docs.ccxt.com/?id=open-interest-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOpenInterests(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object request = new java.util.HashMap<String, Object>() {{}};
            symbols = this.marketSymbols(symbols);
            Object marketIds = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbols, null)))
            {
                marketIds = this.marketIds(symbols);
                Helpers.addElementToObject(request, "symbols", String.join((String)",", (java.util.List<String>)marketIds));
            }
            Object response = (this.publicGetPublicFuturesInfo(this.extend(request, parameters))).join();
            //
            //     {
            //         "BTCUSDT_PERP": {
            //             "contract_type": "perpetual",
            //             "mark_price": "97291.83",
            //             "index_price": "97298.61",
            //             "funding_rate": "-0.000183473092423284",
            //             "open_interest": "94.1503",
            //             "next_funding_time": "2024-12-20T08:00:00.000Z",
            //             "indicative_funding_rate": "-0.00027495203277752",
            //             "premium_index": "-0.000789474900583786",
            //             "avg_premium_index": "-0.000683473092423284",
            //             "interest_rate": "0.0001",
            //             "timestamp": "2024-12-20T04:57:33.693Z"
            //         }
            //     }
            //
            Object results = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object markets = Helpers.objectKeys(response);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(markets)); i++)
            {
                Object marketId = Helpers.GetValue(markets, i);
                Object marketInner = this.safeMarket(marketId);
                ((java.util.List<Object>)results).add(this.parseOpenInterest(Helpers.GetValue(response, marketId), marketInner));
            }
            return this.filterByArray(results, "symbol", symbols);
        });

    }

